def main():
    data = yaml.safe_load(YAML_PATH.read_text())
    sources = data.get("sources", [])
    print(f"Existing sources: {len(sources)}")

    # Add industry_fit_score to existing entries
    patched = 0
    for src in sources:
        if "industry_fit_score" not in src:
            org_type = src.get("organization_type", "unknown")
            src["industry_fit_score"] = FIT_SCORES.get(org_type, 30)
            patched += 1
    print(f"Patched industry_fit_score on {patched} entries")

    # Deduplicate by source_id
    existing_ids = {s.get("source_id") for s in sources}
    added = 0
    for new_src in NEW_SOURCES:
        if new_src["source_id"] not in existing_ids:
            sources.append(new_src)
            existing_ids.add(new_src["source_id"])
            added += 1
    print(f"Added {added} new sources")
    print(f"Total sources: {len(sources)}")

    # Count by category
    from collections import Counter
    org_counts = Counter(s.get("organization_type", "unknown") for s in sources)
    ca = sum(1 for s in sources if s.get("country") == "CA")
    us = sum(1 for s in sources if s.get("country") == "US")
    print(f"\nCanada: {ca}, US: {us}")
    for t, c in org_counts.most_common():
        print(f"  {t}: {c}")

    # Update the YAML header comment with new count
    header = data.get("_header", "")

    data["sources"] = sources
    YAML_PATH.write_text(yaml.dump(data, default_flow_style=False, allow_unicode=True, sort_keys=False, width=120))
    print(f"\nWritten to {YAML_PATH}")


if __name__ == "__main__":
    main()
